{
  "module": "01-layout-navigation.md",
  "group": "01 -- Layout & Navigation (布局与导航)",
  "apiCount": 12,
  "apis": [
    {
      "name": "Column",
      "purpose": "垂直方向线性布局容器，设置子组件间距和对齐方式",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "水平方向线性布局容器，设置子组件间距和对齐方式",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
