      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动容器，内容超出尺寸时可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "List",
      "purpose": "列表容器，连续呈现同类数据，支持懒加载",
      "anchor": "list",
      "status": "found"
    },
    {
      "name": "ListItem",
      "purpose": "列表项组件，必须配合List使用",
      "anchor": "listitem",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，自动填充容器空余空间",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分隔不同内容块",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Tabs",
      "purpose": "页签内容视图切换容器，每个页签对应一个TabContent",
      "anchor": "tabs",
      "status": "found"
    },
    {
      "name": "TabContent",
      "purpose": "对应一个切换页签的内容视图，仅在Tabs中使用",
      "anchor": "tabcontent",
      "status": "found"
    },
    {
      "name": "Navigation",
      "purpose": "路由导航根视图容器，支持标题栏、内容区和工具栏",
      "anchor": "navigation",
      "status": "found"
    },
    {
      "name": "NavRouter",
      "purpose": "导航点击响应组件（已停止维护）",
      "anchor": "navrouter",
      "status": "found"
    },
    {
      "name": "PageTransition / pageTransition",
      "purpose": "页面间转场动效，PageTransitionEnter入场，PageTransitionExit退场",
      "anchor": "pagetransition",
      "status": "found"
    }
  ],
  "notableFindings": [
    "NavRouter 自 API 13 起废弃，推荐使用 NavPathStack + navDestination 替代",
    "Navigation 支持两种模式：简单模式（搭配 NavRouter，API 9 起）和导航栈模式（搭配 NavPathStack，API 10 起推荐）",
    "All layout & navigation components listed are built-in ArkUI components and do not require explicit imports",
    "PageTransition 需在 @Entry 组件的 pageTransition() 生命周期函数中使用",
    "Blank 仅当父组件为 Row/Column/Flex 时生效"
  ],
  "missingApis": []
}

{
  "module": "02-state-reactive.md",
  "group": "02 — State & Reactivity (状态与响应式)",
  "apiCount": 8,
  "apis": [
    {
      "name": "@State",
      "purpose": "组件内可变状态声明装饰器，触发 UI 刷新",
      "anchor": "@state",
      "status": "found"
    },
    {
      "name": "@Prop",
      "purpose": "父组件向子组件传递的单向数据绑定装饰器",
      "anchor": "@prop",
      "status": "found"
    },
    {
      "name": "@Link",
      "purpose": "父组件与子组件之间的双向数据绑定装饰器",
      "anchor": "@link",
      "status": "found"
    },
    {
      "name": "@Provide / @Consume",
      "purpose": "跨组件层级（祖先-后代）的状态传递与同步装饰器",
      "anchor": "@provide-/-@consume",
      "status": "found"
    },
    {
      "name": "@Watch",
      "purpose": "监听状态变量变化并触发回调装饰器",
      "anchor": "@watch",
      "status": "found"
    },
    {
      "name": "@StorageLink / @StorageProp",
      "purpose": "与 AppStorage 全局 UI 状态存储的双向/单向绑定装饰器",
      "anchor": "@storagelink-/-@storageprop",
      "status": "found"
    },
    {
      "name": "AppStorage / LocalStorage",
      "purpose": "应用全局（AppStorage）和页面级（LocalStorage）UI 状态存储",
      "anchor": "appstorage-/-localstorage",
      "status": "found"
    },
    {
      "name": "@LocalStorageLink / @LocalStorageProp",
      "purpose": "与 LocalStorage 页面级存储的双向/单向绑定装饰器",
      "anchor": "@localstoragelink-/-@localstorageprop",
      "status": "found"
    }
  ],
  "notableFindings": [
    "@State, @Prop, @Link, @Provide/@Consume, @StorageLink/@StorageProp, @LocalStorageLink/@LocalStorageProp 均为 ArkUI 内置装饰器 — 无独立 API 参考文档，签名和用法提取自组件文档示例",
    "仅 @Watch 在 03_状态变量变化监听.md 中有独立签名定义：Watch: (value: string) => PropertyDecorator",
    "@Provide 支持 allowOverride 参数（API 11+），定义在 ProvideOptions 接口中（02_状态管理V1装饰器参数.md）",
    "AppStorage 和 LocalStorage 在 01_应用级变量的状态管理.md 中有完整的 API 定义，包括全部方法和参数说明",
    "V1 装饰器从 API 7 开始支持；卡片支持 API 9+，元服务支持 API 11+；ref/setAndRef 等高级方法在 API 12 新增",
    "V2 状态管理 API（@ohos.arkui.StateManagement）包含 AppStorageV2、PersistenceV2、UIUtils，从 @kit.ArkUI 导入（API 12+），本次 api_list 未包含但值得关注"
  ],
  "missingApis": []
}

{
  "module": "03-data-persistence.md",
  "group": "03 — Data Persistence (数据持久化)",
  "apiCount": 5,
  "apis": [
    {
      "name": "@ohos.data.preferences (PreferenceKit)",
      "purpose": "Key-Value持久化存储轻量级数据，支持数字/字符串/布尔及其数组，需主动调用flush落盘",
      "anchor": "ohosdatapreferences-preferencekit",
      "status": "found"
    },
    {
      "name": "@ohos.data.relationalStore (RDB)",
      "purpose": "基于SQLite的关系型数据库，支持增删改查和SQL语句，建议单条数据不超过2MB",
      "anchor": "ohosdatarelationalstore-rdb",
      "status": "found"
    },
    {
      "name": "@ohos.file.fs (fileIo)",
      "purpose": "文件系统基础操作，包括文件的读写、目录管理、文件信息统计、流式读写等",
      "anchor": "ohosfilefs-fileio",
      "status": "found"
    },
    {
      "name": "PersistentStorage",
      "purpose": "将AppStorage中的属性持久化到文件中，实现跨应用生命周期的状态持久化",
      "anchor": "persistentstorage",
      "status": "found"
    },
    {
      "name": "Environment",
      "purpose": "获取系统内置环境变量（语言、颜色模式、字体等）并存入AppStorage",
      "anchor": "environment",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Preferences的XML模式需要主动调用flush()才能持久化，GSKV模式实时落盘。Preferences不支持进程并发安全。",
    "RDB数据库创建后不允许修改加密参数encrypt。单次查询数据量建议不超过5000条，大数据量场景推荐在TaskPool中查询。",
    "fileIo操作前需通过context.filesDir获取沙箱路径。从API 22开始支持传入URI作为参数。",
    "PersistentStorage/Environment是全局API无需导入，调用时机应在AppStorage访问之前。",
    "@Env装饰器（API 22+）是新的响应式环境变量机制，使用SystemProperties枚举值，与全局Environment API不同。",
    "'@ohos.file.fs'的导入模块为@kit.CoreFileKit，而非@kit.ArkData，与数据类API不同。"
  ],
  "missingApis": []
}

